import { resolveMergeConflict } from './task11';

describe('resolveMergeConflict', () => {
  it('prioritizes local unconfirmed', () => {
    const result = resolveMergeConflict({
      localUnconfirmed: 'local',
      serverConfirmed: 'server',
      serverDefault: 'default',
    });
    expect(result).toBe('local');
  });

  it('falls back to server confirmed', () => {
    const result = resolveMergeConflict({
      localUnconfirmed: null,
      serverConfirmed: 'server',
      serverDefault: 'default',
    });
    expect(result).toBe('server');
  });

  it('falls back to server default', () => {
    const result = resolveMergeConflict({
      localUnconfirmed: null,
      serverConfirmed: null,
      serverDefault: 'default',
    });
    expect(result).toBe('default');
  });

  it('returns null when all are null', () => {
    const result = resolveMergeConflict({
      localUnconfirmed: null,
      serverConfirmed: null,
      serverDefault: null,
    });
    expect(result).toBeNull();
  });
});
